// 종목/리그 랜덤 선택 + 말투 스타일 랜덤 선택
// ESPN API (해외 리그, 키 없음), TheSportsDB (한국 리그, 키: 123), football-data.org (축구 순위 보조)
const LEAGUES = [
  // ESPN 해외 축구
  { sport: 'soccer', league: 'eng.1', name: 'Premier League', apiType: 'espn', sportPath: 'soccer' },
  { sport: 'soccer', league: 'esp.1', name: 'La Liga', apiType: 'espn', sportPath: 'soccer' },
  { sport: 'soccer', league: 'ita.1', name: 'Serie A', apiType: 'espn', sportPath: 'soccer' },
  { sport: 'soccer', league: 'ger.1', name: 'Bundesliga', apiType: 'espn', sportPath: 'soccer' },
  { sport: 'soccer', league: 'fra.1', name: 'Ligue 1', apiType: 'espn', sportPath: 'soccer' },
  // ESPN 농구
  { sport: 'basketball', league: 'nba', name: 'NBA', apiType: 'espn', sportPath: 'basketball/nba' },
  // ESPN 야구
  { sport: 'baseball', league: 'mlb', name: 'MLB', apiType: 'espn', sportPath: 'baseball/mlb' },
  // TheSportsDB 한국 리그
  { sport: 'soccer', league: '4491', name: 'K League 1', apiType: 'thesportsdb', sportPath: 'soccer' },
  { sport: 'baseball', league: '4407', name: 'KBO', apiType: 'thesportsdb', sportPath: 'baseball' }
];

// football-data.org 리그 매핑 (축구 순위용)
const FDO_LEAGUE_MAP = {
  'eng.1': 'PL',
  'esp.1': 'PD',
  'ita.1': 'SA',
  'ger.1': 'BL1',
  'fra.1': 'FL1'
};

const idx = Math.floor(Math.random() * LEAGUES.length);
const sel = LEAGUES[idx];

const TONE_STYLES = [
  {
    name: '형',
    guide: '반말 사용, 친근하고 확신에 찬 말투. "야 이거 봐", "이거 무조건이야", "형이 알려줄게" 스타일.',
    examples: ['야 이거 봐 진짜 미쳤어', '이거 무조건이야 내가 장담해', '형이 알려줄게 잘 들어']
  },
  {
    name: '빡침',
    guide: '반말 사용, 답답하고 빡친 말투. "아 진짜 제발 데이터 좀 보고 찍어", "이걸 왜 몰라?" 스타일.',
    examples: ['아 진짜 제발 데이터 좀 보고 찍어', '이걸 왜 몰라 진짜 답답해', '아니 이게 말이 되냐고']
  },
  {
    name: 'ASMR',
    guide: '존댓말 사용, 차분하고 전문적인 말투. "심상치 않습니다", "주목해야 할 부분이 있습니다" 스타일.',
    examples: ['여러분 이건 심상치 않습니다', '주목해야 할 부분이 있습니다', '데이터가 말해주고 있습니다']
  }
];

const toneIdx = Math.floor(Math.random() * TONE_STYLES.length);
const selectedTone = TONE_STYLES[toneIdx];

const today = new Date().toISOString().split('T')[0]; // YYYY-MM-DD
const todayCompact = today.replace(/-/g, ''); // YYYYMMDD

let fixturesUrl = '';
let standingsUrl = '';
let useFdo = false;
let fdoLeagueCode = '';

if (sel.apiType === 'espn') {
  fixturesUrl = 'https://site.api.espn.com/apis/site/v2/sports/' + sel.sportPath + '/scoreboard?dates=' + todayCompact;
  if (sel.sport === 'soccer') {
    fixturesUrl += '&league=' + sel.league;
    // football-data.org로 순위 조회
    fdoLeagueCode = FDO_LEAGUE_MAP[sel.league] || '';
    if (fdoLeagueCode) {
      useFdo = true;
      standingsUrl = 'https://api.football-data.org/v4/competitions/' + fdoLeagueCode + '/standings';
    } else {
      standingsUrl = 'https://site.api.espn.com/apis/v2/sports/' + sel.sportPath + '/standings?league=' + sel.league;
    }
  } else {
    standingsUrl = 'https://site.api.espn.com/apis/v2/sports/' + sel.sportPath + '/standings';
  }
} else {
  // TheSportsDB
  fixturesUrl = 'https://www.thesportsdb.com/api/v1/json/123/eventsround.php?id=' + sel.league + '&r=1&s=2025-2026';
  standingsUrl = 'https://www.thesportsdb.com/api/v1/json/123/lookuptable.php?l=' + sel.league + '&s=2025-2026';
}

return [{
  json: {
    apiType: sel.apiType,
    sport: sel.sport,
    league: { id: sel.league, name: sel.name },
    toneStyle: selectedTone.name,
    toneGuide: selectedTone.guide,
    toneExamples: selectedTone.examples,
    today,
    fixturesUrl,
    standingsUrl,
    useFdo,
    fdoKey: 'e0397df419be4d21b4133e75af030ba6',
    category: 5
  }
}];

// ESPN / TheSportsDB 경기 목록 파싱
const sportData = $('종목 결정').first().json;
const raw = $input.first().json;
const apiType = sportData.apiType;

let parsed = [];

if (apiType === 'espn') {
  const events = raw.events || [];
  if (events.length === 0) {
    throw new Error('오늘 ' + sportData.league.name + ' 경기가 없습니다. 다시 실행해주세요.');
  }
  parsed = events.map(ev => {
    const comp = ev.competitions && ev.competitions[0];
    if (!comp) return null;
    const teams = comp.competitors || [];
    const home = teams.find(t => t.homeAway === 'home') || teams[0] || {};
    const away = teams.find(t => t.homeAway === 'away') || teams[1] || {};
    return {
      fixtureId: ev.id,
      date: ev.date,
      homeTeam: { id: home.id, name: home.team ? home.team.displayName : 'Home' },
      awayTeam: { id: away.id, name: away.team ? away.team.displayName : 'Away' },
      status: ev.status ? ev.status.type.name : '',
      venue: comp.venue ? comp.venue.fullName : ''
    };
  }).filter(Boolean);
} else {
  // TheSportsDB
  const events = raw.events || [];
  if (!events || events.length === 0) {
    throw new Error('오늘 ' + sportData.league.name + ' 경기가 없습니다. 다시 실행해주세요.');
  }
  parsed = events.map(ev => ({
    fixtureId: ev.idEvent,
    date: ev.dateEvent + 'T' + (ev.strTime || '00:00:00'),
    homeTeam: { id: ev.idHomeTeam, name: ev.strHomeTeam },
    awayTeam: { id: ev.idAwayTeam, name: ev.strAwayTeam },
    status: ev.strStatus || '',
    venue: ev.strVenue || ''
  }));
}

// 아직 시작 안 한 경기 필터
const upcoming = parsed.filter(g => {
  const s = (g.status || '').toLowerCase();
  return !s || s === 'scheduled' || s === 'pre' || s === 'ns' || s === 'not started' || s === 'STATUS_SCHEDULED';
});
const gameList = upcoming.length > 0 ? upcoming : parsed;

if (gameList.length === 0) {
  throw new Error('파싱된 경기가 없습니다.');
}

return [{
  json: {
    fixtures: gameList,
    fixtureCount: gameList.length
  }
}];

// ESPN/TheSportsDB는 부상 API를 제공하지 않음
// 빈 결과 반환
return [{
  json: {
    response: [],
    available: false
  }
}];

// ESPN/TheSportsDB는 H2H API를 제공하지 않음
// 빈 결과 반환
return [{
  json: {
    response: [],
    available: false
  }
}];

// 순위 + 이전 픽 데이터 통합 (ESPN/TheSportsDB/football-data.org)
const sportData = $('종목 결정').first().json;
const fixtureData = $('경기 목록 파싱').first().json;
const standingsRaw = $('순위표 조회').first().json;
const injuriesData = $('부상자 조회').first().json;
const h2hData = $('상대전적 조회').first().json;

// 순위 파싱 (3가지 포맷 지원)
let standingsSummary = '';
try {
  if (sportData.useFdo && standingsRaw.standings) {
    // football-data.org 형식
    const table = standingsRaw.standings[0]?.table || [];
    standingsSummary = table.map(s => {
      return s.position + '위 ' + s.team.name + ' (' + s.points + '점, 폼:' + (s.form || '?') + ', ' + s.won + '승' + s.draw + '무' + s.lost + '패)';
    }).join('\n');
  } else if (sportData.apiType === 'espn') {
    // ESPN 형식
    const children = standingsRaw.children || [];
    if (children.length > 0) {
      const entries = children[0]?.standings?.entries || [];
      standingsSummary = entries.slice(0, 20).map((e, i) => {
        const stats = {};
        (e.stats || []).forEach(s => { stats[s.name] = s.value || s.displayValue; });
        return (i+1) + '위 ' + (e.team?.displayName || '?') + ' (' + (stats.points || stats.wins || '?') + '점, ' + (stats.gamesPlayed || stats.wins || '?') + '경기)';
      }).join('\n');
    } else {
      standingsSummary = '순위 데이터 없음';
    }
  } else {
    // TheSportsDB 형식
    const table = standingsRaw.table || [];
    standingsSummary = table.map(s => {
      return s.intRank + '위 ' + s.strTeam + ' (' + s.intPoints + '점, ' + s.intWin + '승' + s.intDraw + '무' + s.intLoss + '패)';
    }).join('\n');
  }
} catch(e) {
  standingsSummary = '순위 데이터 파싱 실패: ' + e.message;
}
if (!standingsSummary) standingsSummary = '순위 데이터 없음';

// 부상자 (현재 미지원)
const injuriesSummary = injuriesData.available ? JSON.stringify(injuriesData.response).substring(0, 1000) : '부상 정보는 현재 API에서 제공하지 않습니다';

// H2H (현재 미지원)
const h2hSummary = h2hData.available ? JSON.stringify(h2hData.response).substring(0, 1000) : '상대전적 정보는 현재 API에서 제공하지 않습니다';

// 이전 픽 데이터
let prevPickResult = '미확인';
let prevMatchup = '';
let prevPick = '';
let isFirstPick = true;
try {
  const sheetData = $('이전 픽 조회').all();
  if (sheetData && sheetData.length > 0) {
    const lastRow = sheetData[sheetData.length - 1].json;
    prevPickResult = lastRow.pickResult || '미확인';
    prevMatchup = lastRow.matchup || '';
    prevPick = lastRow.pick || '';
    isFirstPick = false;
  }
} catch(e) { /* 첫 실행이거나 시트 비어있음 */ }

// 경기 목록 요약
const fixturesSummary = fixtureData.fixtures.map((f, i) => {
  return (i+1) + '. ' + f.homeTeam.name + ' vs ' + f.awayTeam.name + ' (ID: ' + f.fixtureId + ')';
}).join('\n');

return [{
  json: {
    sport: sportData.sport,
    league: sportData.league,
    toneStyle: sportData.toneStyle,
    toneGuide: sportData.toneGuide,
    toneExamples: sportData.toneExamples,
    fixtures: fixtureData.fixtures,
    fixturesSummary,
    standingsSummary,
    injuriesSummary,
    h2hSummary,
    prevPickResult,
    prevMatchup,
    prevPick,
    isFirstPick,
    today: sportData.today,
    category: 5
  }
}];

values.content:
너는 스포츠 분석 전문가야. 아래 경기 목록과 데이터를 보고 가장 흥미로운 1경기를 선택해줘.

## 종목: {{ $json.sport }} / 리그: {{ $json.league.name }}

## 오늘 경기 목록
{{ $json.fixturesSummary }}

## 리그 순위표
{{ $json.standingsSummary }}

## 부상/결장 정보
{{ $json.injuriesSummary }}

## 상대전적
{{ $json.h2hSummary }}

## 선택 기준
- 순위 차이가 적절한 경기 (너무 일방적이지 않은)
- 최근 폼이 흥미로운 팀이 포함된 경기
- 분석 포인트가 많은 경기
- 반전 요소가 있을 수 있는 경기

## 출력 형식 (순수 JSON만, 코드블록 없이)
{ "selectedFixtureId": 경기ID, "homeTeam": "홈팀명", "awayTeam": "어웨이팀명", "reason": "선택 이유 한줄", "angle": "분석 각도 한줄", "hookIdea": "훅 아이디어 한줄" }

