// AI 경기 선택 결과 파싱
const raw = $input.first().json;
let text = '';
if (raw.content && raw.content.parts) {
  text = raw.content.parts[0].text;
} else if (typeof raw === 'string') {
  text = raw;
} else if (raw.text) {
  text = raw.text;
} else {
  text = JSON.stringify(raw);
}

const cleanText = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let data;
try {
  data = JSON.parse(cleanText);
} catch(e) {
  const first = cleanText.indexOf('{');
  const last = cleanText.lastIndexOf('}');
  if (first !== -1 && last > first) {
    data = JSON.parse(cleanText.substring(first, last + 1));
  } else {
    throw new Error('AI 경기 선택 JSON 파싱 실패: ' + cleanText.substring(0, 300));
  }
}

if (!data.selectedFixtureId) {
  throw new Error('selectedFixtureId가 없습니다: ' + JSON.stringify(data));
}

const mergedData = $('데이터 병합').first().json;

// 선택된 경기 찾기
const selectedFixture = mergedData.fixtures.find(f => String(f.fixtureId) === String(data.selectedFixtureId)) || mergedData.fixtures[0];

return [{
  json: {
    selectedFixtureId: data.selectedFixtureId,
    homeTeam: data.homeTeam || selectedFixture.homeTeam.name,
    awayTeam: data.awayTeam || selectedFixture.awayTeam.name,
    matchup: (data.homeTeam || selectedFixture.homeTeam.name) + ' vs ' + (data.awayTeam || selectedFixture.awayTeam.name),
    reason: data.reason || '',
    angle: data.angle || '',
    hookIdea: data.hookIdea || '',
    sport: mergedData.sport,
    league: mergedData.league,
    toneStyle: mergedData.toneStyle,
    toneGuide: mergedData.toneGuide,
    toneExamples: mergedData.toneExamples,
    standingsSummary: mergedData.standingsSummary,
    injuriesSummary: mergedData.injuriesSummary,
    h2hSummary: mergedData.h2hSummary,
    prevPickResult: mergedData.prevPickResult,
    prevMatchup: mergedData.prevMatchup,
    prevPick: mergedData.prevPick,
    isFirstPick: mergedData.isFirstPick,
    today: mergedData.today,
    category: 5
  }
}];

const raw = $input.first().json;
let text = '';
if (raw.content && raw.content.parts) {
  text = raw.content.parts[0].text;
} else if (typeof raw === 'string') {
  text = raw;
} else if (raw.text) {
  text = raw.text;
} else {
  text = JSON.stringify(raw);
}

function cleanGeminiJson(raw) {
  let s = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const first = s.indexOf('{');
  const last = s.lastIndexOf('}');
  if (first !== -1 && last > first) {
    s = s.substring(first, last + 1);
  }
  let result = '';
  let inStr = false;
  let esc = false;
  for (let i = 0; i < s.length; i++) {
    const c = s[i];
    if (esc) { result += c; esc = false; continue; }
    if (c === '\\' && inStr) { result += c; esc = true; continue; }
    if (c === '"') { inStr = !inStr; result += c; continue; }
    if (inStr) {
      if (c === '\n' || c === '\r') { result += ' '; continue; }
      if (c === '\t') { result += ' '; continue; }
      if (c.charCodeAt(0) < 0x20) { continue; }
    }
    result += c;
  }
  result = result.replace(/,(\s*[}\]])/g, '$1');
  return result;
}

let cleanText = cleanGeminiJson(text);
let data;

try {
  data = JSON.parse(cleanText);
} catch (e1) {
  try {
    let fixed = cleanText
      .replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"')
      .replace(/[\u2018\u2019\u201A\u201B\u2032\u2035]/g, "'")
      .replace(/^\uFEFF/, '');
    data = JSON.parse(fixed);
  } catch (e2) {
    const posMatch = e1.message.match(/position (\d+)/);
    const pos = posMatch ? parseInt(posMatch[1]) : 0;
    const start = Math.max(0, pos - 80);
    const end = Math.min(cleanText.length, pos + 80);
    const around = cleanText.substring(start, end);
    throw new Error(
      'JSON 파싱 실패: ' + e1.message + '\n' +
      '--- 에러 위치(' + pos + ') 주변 ---\n' + around + '\n' +
      '처음 300자: ' + cleanText.substring(0, 300)
    );
  }
}

// images + subtitles 검증
if (!data.images || data.images.length < 4) {
  throw new Error('images must have at least 4 items, got: ' + (data.images ? data.images.length : 0));
}
if (!data.subtitles || data.subtitles.length < 6) {
  throw new Error('subtitles must have at least 6 items, got: ' + (data.subtitles ? data.subtitles.length : 0));
}

const VALID_MOODS = ['thinking', 'excited', 'shocked', 'sad', 'angry', 'cool', 'celebrating', 'snacking', 'speechless', 'smoking', 'disappointed', 'thumbsup', 'crying', 'desperate', 'bored', 'suspicious', 'money'];

data.images = data.images.map((img, idx) => {
  if (!img.visual_type || !['image', 'meme'].includes(img.visual_type)) {
    img.visual_type = 'image';
  }
  if (img.visual_type === 'meme') {
    if (!img.meme_mood || !VALID_MOODS.includes(img.meme_mood)) {
      img.meme_mood = VALID_MOODS[idx % VALID_MOODS.length];
    }
  } else {
    img.meme_mood = '';
    if (!img.keyword) {
      img.keyword = 'sports stadium';
    }
  }
  return img;
});

const fullDialogue = data.subtitles.join(' ');
const memeCount = data.images.filter(i => i.visual_type === 'meme').length;

const promptData = $('스포츠 프롬프트 생성').first().json;

return [{
  json: {
    hook_title: data.hook_title,
    images: data.images,
    subtitles: data.subtitles,
    Subject: data.Subject,
    Caption: data.Caption,
    Comment: data.Comment,
    fullDialogue,
    Narration: fullDialogue,
    imageCount: data.images.length,
    subtitleCount: data.subtitles.length,
    memeCount,
    Status: '생성 중',
    generatedAt: new Date().toISOString(),
    sport: promptData.sport,
    league: promptData.league.name,
    matchup: promptData.matchup,
    matchDate: promptData.today,
    fixtureId: promptData.selectedFixtureId,
    pick: data.pick || '',
    pickDetail: data.pickDetail || '',
    confidence: data.confidence || '보통',
    toneStyle: promptData.toneStyle,
    prevPickResult: promptData.prevPickResult || '미확인',
    category: 5
  }
}];

const items = $input.all();

return items.map(item => {
  const audioUrl = item.json.audio_url;
  const durationSec = item.json.duration_sec;
  const timestamps = item.json.timestamps || [];

  if (!audioUrl) {
    throw new Error('TTS 응답에 audio_url이 없습니다: ' + JSON.stringify(item.json));
  }

  return {
    json: {
      audio_url: audioUrl,
      duration_sec: durationSec,
      timestamps,
      ...item.json
    }
  };
});

const data = $('콘텐츠 파싱').first().json;
const images = data.images || [];

// images 배열만 세그먼트로 분리 (이미지 검색용)
return images.map((img, i) => ({
  json: {
    index: i,
    keyword: img.keyword || 'abstract background',
    visual_type: img.visual_type || 'image',
    meme_mood: img.meme_mood || '',
  }
}));

// 밈 카탈로그: MinIO에 호스팅된 밈/리액션 영상 URL (35개)
const MEME_CATALOG = {
  thinking: [
