    'http://76.13.182.180:9000/memes/thinking/detective_pikachu_twist.png',
    'http://76.13.182.180:9000/memes/thinking/roll_safe_think.jpg',
    'http://76.13.182.180:9000/memes/thinking/simpsons_lenny_praying.jpg',
  ],
  excited: [
