function escapeDrawtext(text) {
  if (!text) return '';
  // 이모지 제거 (NanumGothicBold에 이모지 글리프 없음)
  text = text.replace(/[\u{1F600}-\u{1F64F}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}\u{1F1E0}-\u{1F1FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}\u{FE00}-\u{FE0F}\u{1F900}-\u{1F9FF}\u{1FA00}-\u{1FA6F}\u{1FA70}-\u{1FAFF}\u{200D}\u{20E3}\u{FE0F}]/gu, '').trim();
  return text.replace(/\\/g, '\\\\').replace(/'/g, '\u2019').replace(/"/g, '\u201D').replace(/:/g, '\\:').replace(/;/g, '\\;').replace(/,/g, '\\,').replace(/\[/g, '\\[').replace(/\]/g, '\\]').replace(/\n/g, ' ');
}
function escapeDrawtextMultiline(text) {
  if (!text) return '';
  text = text.replace(/[\u{1F600}-\u{1F64F}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}\u{1F1E0}-\u{1F1FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}\u{FE00}-\u{FE0F}\u{1F900}-\u{1F9FF}\u{1FA00}-\u{1FA6F}\u{1FA70}-\u{1FAFF}\u{200D}\u{20E3}\u{FE0F}]/gu, '').trim();
  return text.replace(/\\/g, '\\\\').replace(/'/g, '\u2019').replace(/"/g, '\u201D').replace(/:/g, '\\:').replace(/;/g, '\\;').replace(/,/g, '\\,').replace(/\[/g, '\\[').replace(/\]/g, '\\]');
}
function wrapSubtitle(text, maxLen) {
  if (!text) return '';
  const words = text.split(' ');
  let lines = [];
  let currentLine = '';
  for (const word of words) {
    if (currentLine.length + word.length > maxLen && currentLine.length > 0) {
      lines.push(currentLine.trim());
      currentLine = word + ' ';
    } else {
      currentLine += word + ' ';
    }
  }
  if (currentLine) lines.push(currentLine.trim());
  return lines.join('\n');
}

