// === 자막: 글자수 비율 + min/max 보정 타이밍 ===
const MIN_SUB_DUR = 0.70;
const MAX_SUB_DUR = 1.80;

// 1단계: 글자수 비율로 rawDur 계산
const totalChars = subtitles.reduce((sum, s) => {
  return sum + s.replace(/<[^>]*>?/gm, '').replace(/\s+/g, '').length;
}, 0);

let subMeta = subtitles.map((raw, i) => {
  const clean = raw.replace(/<[^>]*>?/gm, '');
  const chars = clean.replace(/\s+/g, '').length;
  const ratio = totalChars > 0 ? chars / totalChars : 1 / subtitles.length;
  const rawDur = ratio * audioDuration;
  return { index: i, raw, clean, chars, rawDur, hasEm: raw.includes('<em>') };
});

// 2단계: min/max 클램프 + 차이 계산
let excess = 0;
let clampedDurs = subMeta.map(s => {
  if (s.rawDur < MIN_SUB_DUR) {
    excess += s.rawDur - MIN_SUB_DUR;
    return MIN_SUB_DUR;
  } else if (s.rawDur > MAX_SUB_DUR) {
    excess += s.rawDur - MAX_SUB_DUR;
    return MAX_SUB_DUR;
  }
  return s.rawDur;
});

// 3단계: 클램프 안 걸린 자막에 비례 재분배
if (Math.abs(excess) > 0.001) {
  const unclamped = clampedDurs.map((d, i) => d !== MIN_SUB_DUR && d !== MAX_SUB_DUR ? i : -1).filter(i => i >= 0);
  const unclampedTotal = unclamped.reduce((sum, i) => sum + clampedDurs[i], 0);
  if (unclampedTotal > 0) {
    for (const i of unclamped) {
      const share = (clampedDurs[i] / unclampedTotal) * excess;
      clampedDurs[i] = Math.max(MIN_SUB_DUR, Math.min(MAX_SUB_DUR, clampedDurs[i] + share));
    }
  }
}

