  const sfxMixLabels = sfxInputs.map((_, i) => `[sfx${i}]`).join('');
  filterParts.push(`${sfxMixLabels}amix=inputs=${sfxCount}:duration=longest:normalize=0[sfx_mix]`);
  filterParts.push(`[tts_raw][bgm][sfx_mix]amix=inputs=3:duration=longest:weights=1 1 0.8:normalize=0[amain]`);
} else {
  filterParts.push(`[tts_raw][bgm]amix=inputs=2:duration=longest:weights=1 1:normalize=0[amain]`);
}

// === 아웃트로 비디오 concat ===
if (outroIdx >= 0) {
  filterParts.push(`[${outroIdx}:v]scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black,setsar=1,format=yuv420p,fps=30[voutro]`);
  filterParts.push(`[vconcat]format=yuv420p[vmain_fmt]`);
  filterParts.push(`[vmain_fmt][voutro]concat=n=2:v=1:a=0[vwithoutro]`);
} else {
  filterParts.push(`[vconcat]null[vwithoutro]`);
}

// === 오디오: 메인만 사용, 아웃트로 구간은 무음 패딩 ===
if (outroIdx >= 0) {
  const fullDuration = totalDuration + outroDuration;
  filterParts.push(`[amain]apad=whole_dur=${fullDuration.toFixed(2)}[afinal]`);
} else {
  filterParts.push(`[amain]anull[afinal]`);
}

// 자막 오버레이 (상단 제목 + 하단 자막 + 훅)
let overlayFilter = `[vwithoutro]drawbox=y=40:w=1080:h=280:color=#000000@1.0:t=fill,drawtext=expansion=none:text='${escapeDrawtext(hookClean)}':fontsize=72:fontcolor=white:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=120:line_spacing=12`;

// 자막 (글자수 비율 기반 타이밍, 이미지 전환과 독립)
for (const sub of subSegments) {
  const subText = escapeDrawtext(wrapSubtitle(sub.clean, 12));
  const startT = sub.start.toFixed(2);
  const endT = (sub.start + sub.duration).toFixed(2);
  overlayFilter += `,drawtext=expansion=none:text='${subText}':fontsize=80:fontcolor=white:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=h-280:borderw=4:bordercolor=black:enable='between(t,${startT},${endT})'`;
}

// 훅 자막
const hookEscaped = escapeDrawtextMultiline(wrapSubtitle(hookClean, 10));
const hookEndT = 2.5;
overlayFilter += `,drawbox=y=(h-400)/2:w=1080:h=400:color=#000000@0.7:t=fill:enable='between(t,0,${hookEndT})'`;
overlayFilter += `,drawtext=expansion=none:text='${hookEscaped}':fontsize=80:fontcolor=#CCFF00:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=(h-th)/2:borderw=4:bordercolor=black:enable='between(t,0,${hookEndT})'`;
// 아웃트로 CTA 자막 (아웃트로 구간에만 표시)
if (outroIdx >= 0) {
  totalDuration += outroDuration;  // CTA 계산 전에 아웃트로 길이 반영
  const ctaText = escapeDrawtextMultiline(wrapSubtitle(outroCta, 14));
  const outroStartT = (totalDuration - outroDuration).toFixed(2);
  const outroEndT = totalDuration.toFixed(2);
  overlayFilter += `,drawbox=y=h-350:w=1080:h=120:color=#000000@0.7:t=fill:enable='between(t,${outroStartT},${outroEndT})'`;
  overlayFilter += `,drawtext=expansion=none:text='${ctaText}':fontsize=60:fontcolor=#CCFF00:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=h-320:borderw=3:bordercolor=black:enable='between(t,${outroStartT},${outroEndT})'`;
}

overlayFilter += '[vfinal]';
filterParts.push(overlayFilter);

const nca_payload = {
  inputs,
  filters: [{ filter: filterParts.join(';') }],
  outputs: [{
    options: [
      { option: "-map", argument: "[vfinal]" }, { option: "-map", argument: "[afinal]" },
      { option: "-c:v", argument: "libx264" }, { option: "-preset", argument: "fast" }, { option: "-crf", argument: "23" },
      { option: "-c:a", argument: "aac" }, { option: "-b:a", argument: "192k" },
      { option: "-pix_fmt", argument: "yuv420p" }, { option: "-movflags", argument: "+faststart" }, { option: "-t", argument: totalDuration.toFixed(2) }
    ],
    file_name: "kkultip_shorts_final.mp4"
  }]
};

return [{
  json: {
    nca_payload,
    totalDuration,
    imageCount: imgSegments.length,
    subtitleCount: subSegments.length,
    hookTitle,
    subject: $('콘텐츠 파싱').first().json.Subject,
    caption: $('콘텐츠 파싱').first().json.Caption,
    comment: $('콘텐츠 파싱').first().json.Comment,
    category,
    outroFile,
    debugCategory: {
      from_contentParsing: $('콘텐츠 파싱').first().json.category,
      from_topicParsing: $('경기 선택 파싱').first().json.category,
      usedCategory: category,
      selectedOutro: outroFile || 'none',
      selectedCta: outroCta || 'none'
    }
  }
}];

// NCA 결과 처리
const result = $input.first().json;
const prevData = $('NCA 데이터 준비').first().json;

let videoUrl = '';
if (Array.isArray(result.response)) {
  videoUrl = result.response[0]?.file_url || '';
} else if (typeof result.response === 'string') {
  videoUrl = result.response;
} else {
  videoUrl = result.output_url || result.url || result.video_url || result.file_url || '';
}

if (!videoUrl) {
  throw new Error('NCA 영상 제작 결과 URL 없음: ' + JSON.stringify(result).substring(0, 500));
}

return [{
  json: {
    '영상 URL': videoUrl,
    Status: '완료',
    topic: $('경기 선택 파싱').first().json.matchup,
    category: prevData.category,
    outro_file: prevData.outroFile || '',
  }
}];
